<?php

namespace Nexhbp\HimalayanBank;

class SecurityData {

	public static string $TokenType = 'JWT';
	public static string $JWSAlgorithm = 'PS256';
	public static string $JWEAlgorithm = 'RSA-OAEP';
	public static string $JWEEncrptionAlgorithm = 'A128CBC-HS256';

	// PACO keys (hardcoded, production-only).
	private static string $PacoEncryptionPublicKey = '';
	private static string $PacoSigningPublicKey = '';

	// Hardcoded PACO private keys (not used on merchant side; kept for completeness).
	private static string $PacoEncryptionPrivateKey = '';
	private static string $PacoSigningPrivateKey = '';


	//private keys
	private static string $MerchantSigningPrivateKey = '';
	private static string $MerchantEncryptionPrivateKey = '';
	private static array $runtime = array();

	/**
	 * Initialise runtime settings from the BA plugin options array.
	 * Must be called before any get_* method is used.
	 */
	public static function init_from_settings( array $settings ): void {
		self::$runtime = $settings;
	}

	public static function get_merchant_id(): string {
		return self::$runtime['merchant_id'] ?? '';
	}

	public static function get_encryption_key_id(): string {
		return self::$runtime['encryption_key'] ?? '';
	}

	public static function get_access_token(): string {
		return self::$runtime['access_token'] ?? '';
	}

	public static function get_merchant_signing_private_key(): string {
		// Private signing key is hardcoded in code (do not expose via WP admin UI).
		return self::$MerchantSigningPrivateKey;
	}

	public static function get_merchant_signing_public_key(): string {
		return self::$runtime['merchant_sign_public_key'] ?? '';
	}

	public static function get_merchant_encryption_public_key(): string {
		return self::$runtime['merchant_encrypt_public_key'] ?? '';
	}

	public static function get_paco_encryption_public_key(): string {
		return self::$PacoEncryptionPublicKey;
	}

	public static function get_paco_signing_public_key(): string {
		return self::$PacoSigningPublicKey;
	}

	public static function get_merchant_decryption_private_key(): string {
		// Private decryption key is hardcoded in code (do not expose via WP admin UI).
		return self::$MerchantEncryptionPrivateKey;
	}
}
